/** Client-side auth: token storage, login, logout. */

import { fetchWithRetry } from './http';

const TOKEN_KEY = 'taskhub.token';

export function storeToken(token: string): void {
  window.localStorage.setItem(TOKEN_KEY, token);
}

export function getToken(): string | null {
  return window.localStorage.getItem(TOKEN_KEY);
}

export function clearToken(): void {
  window.localStorage.removeItem(TOKEN_KEY);
}

export async function login(email: string, password: string): Promise<void> {
  const result = await fetchWithRetry<{ token: string }>('/api/login', {
    method: 'POST',
    body: JSON.stringify({ email, password }),
  });
  storeToken(result.token);
}

"""User model."""

from dataclasses import dataclass


@dataclass
class User:
    id: int
    email: str
    name: str


def user_from_row(row) -> User:
    """Build a User from a sqlite3.Row."""
    return User(id=row["id"], email=row["email"], name=row["name"])

"""SQLite database access layer."""

import sqlite3

_SCHEMA = """
CREATE TABLE IF NOT EXISTS tasks (
    id INTEGER PRIMARY KEY,
    title TEXT NOT NULL,
    status TEXT NOT NULL DEFAULT 'open',
    owner_id INTEGER,
    created_at TEXT NOT NULL
);
CREATE TABLE IF NOT EXISTS users (
    id INTEGER PRIMARY KEY,
    email TEXT UNIQUE NOT NULL,
    name TEXT NOT NULL
);
"""


class Database:
    """Thin wrapper around sqlite3 with row factories."""

    def __init__(self, path: str) -> None:
        self.path = path
        self._conn: sqlite3.Connection | None = None

    def connect(self) -> sqlite3.Connection:
        """Open (and memoize) the database connection, creating the schema."""
        if self._conn is None:
            self._conn = sqlite3.connect(self.path)
            self._conn.row_factory = sqlite3.Row
            self._conn.executescript(_SCHEMA)
        return self._conn

    def execute(self, sql: str, params: tuple = ()) -> sqlite3.Cursor:
        return self.connect().execute(sql, params)

    def fetch_all(self, sql: str, params: tuple = ()) -> list[sqlite3.Row]:
        return self.execute(sql, params).fetchall()

    def close(self) -> None:
        if self._conn is not None:
            self._conn.close()
            self._conn = None

"""Application wiring and entry point."""

from pyserver.config import Settings, load_config
from pyserver.db import Database
from pyserver.routes import register_routes


class App:
    """Minimal dispatch-table web app (framework-free for the fixture)."""

    def __init__(self, settings: Settings) -> None:
        self.settings = settings
        self.db = Database(settings.database_path)
        self._routes: dict[tuple[str, str], object] = {}

    def route(self, method: str, path: str, handler) -> None:
        self._routes[(method, path)] = handler

    def dispatch(self, method: str, path: str, payload: dict) -> object:
        handler = self._routes[(method, path)]
        return handler(self.db, payload)


def create_app(config_path: str | None = None) -> App:
    """Build the app: load config, connect the database, register routes."""
    settings = load_config(config_path)
    app = App(settings)
    app.db.connect()
    register_routes(app)
    return app


def run() -> None:
    """Start the server (fixture stub: builds the app and reports readiness)."""
    app = create_app()
    print(f"taskhub listening on {app.settings.host}:{app.settings.port}")

"""Tiny in-memory TTL cache used for hot lookups (e.g. users by id)."""

import time
from typing import Any, Callable


class MemoCache:
    """Dict-backed cache with per-entry expiry. Not thread-safe."""

    def __init__(self, ttl_seconds: float = 60.0, clock: Callable[[], float] = time.monotonic) -> None:
        self.ttl = ttl_seconds
        self._clock = clock
        self._entries: dict[Any, tuple[float, Any]] = {}

    def get(self, key: Any) -> Any | None:
        entry = self._entries.get(key)
        if entry is None:
            return None
        expires_at, value = entry
        if self._clock() >= expires_at:
            del self._entries[key]
            return None
        return value

    def put(self, key: Any, value: Any) -> None:
        self._entries[key] = (self._clock() + self.ttl, value)

    def clear(self) -> None:
        self._entries.clear()

