/** Typed API client for the taskhub server. */

import { request } from './http';
import type { Task, User } from './types';

const BASE = '/api';

export async function fetchTasks(status?: string): Promise<Task[]> {
  const query = status ? `?status=${encodeURIComponent(status)}` : '';
  return request<Task[]>(`${BASE}/tasks${query}`);
}

export async function createTask(title: string, ownerId?: number): Promise<Task> {
  return request<Task>(`${BASE}/tasks`, {
    method: 'POST',
    body: JSON.stringify({ title, owner_id: ownerId }),
  });
}

export async function fetchUser(id: number): Promise<User> {
  return request<User>(`${BASE}/users?id=${id}`);
}

